import { createDomElement } from '@slickgrid-universal/utils';
import '../core/index.js';
import { sumTotalsDollarFormatter } from './sumTotalsDollarFormatter.js';
export const sumTotalsDollarBoldFormatter = (totals, columnDef, grid) => {
  const textContent = sumTotalsDollarFormatter(totals, columnDef, grid);
  if (textContent) {
    return createDomElement('span', {
      style: {
        fontWeight: 'bold'
      },
      textContent
    });
  }
  return '';
};
