import { createDomElement } from '@slickgrid-universal/utils';
import '../core/index.js';
import { sumTotalsFormatter } from './sumTotalsFormatter.js';
export const sumTotalsBoldFormatter = (totals, columnDef, grid) => {
  const textContent = sumTotalsFormatter(totals, columnDef, grid);
  if (textContent) {
    return createDomElement('span', {
      style: {
        fontWeight: 'bold'
      },
      textContent
    });
  }
  return '';
};
